(3, 11, 2, '袠屑斜邪', 1, 0, '2026-06-22 11:59:41'),
(12, 17, 2, '携 写芯褌械褉, 邪 屑芯泄 锌邪锌邪 褕邪褏屑邪褌懈褋褌, 写芯泻邪蟹邪薪薪芯!!!!!!', 1, 0, '2026-06-23 23:53:52'),
(100, 100, 2, '袧邪泻芯薪械褑-褌芯 TI 褋薪芯胁邪 褋褌邪薪械褌 谐褉邪薪写懈芯蟹薪褘屑 褋芯斜褘褌懈械屑! 袞写褍 薪械 写芯卸写褍褋褜 褎懈薪邪谢邪 胁 袣芯锌械薪谐邪谐械薪械!', 12, 0, '2026-06-20 08:15:00'),
(101, 100, 1, '40 谢褟屑芯胁 - 褝褌芯 泻芯薪械褔薪芯 泻褉褍褌芯, 薪芯 锌芯褔械屑褍 写芯 褋懈褏 锌芯褉 薪械褌 锌褉褟屑褘褏 褌褉邪薪褋谢褟褑懈泄 薪邪 褉褍褋褋泻芯屑?', 8, 0, '2026-06-20 09:30:00'),
(102, 100, 6, 'Team Spirit 胁 褝褌芯屑 谐芯写褍 锌褉芯褋褌芯 屑邪褕懈薪邪! 小褌邪胁谢褞 薪邪 薪懈褏 胁褋械 写械薪褜谐懈!', 3, 0, '2026-06-20 11:00:00'),
(103, 101, 1, 'PA 芯锌褟褌褜 nerf薪褍谢懈... 袣芯谐写邪 褍卸械 锌械褉械褋褌邪薪褍褌 锌芯褉褌懈褌褜 屑芯械谐芯 谢褞斜懈屑芯谐芯 谐械褉芯褟?', 6, 0, '2026-06-21 12:00:00'),
(104, 101, 2, '袧邪泻芯薪械褑-褌芯 Anti-Mage 锌芯谢褍褔懈谢 buff! 袙褉械屑褟 褎邪褉屑懈褌褜 懈 褌邪褖懈褌褜!', 9, 0, '2026-06-21 13:30:00'),
(105, 102, 6, 'Team Spirit 锌芯泻邪卸械褌 泻谢邪褋褋! 袪芯褋褋懈褟 胁锌械褉械写! 馃嚪馃嚭', 3, 0, '2026-06-22 07:00:00'),
(106, 102, 1, 'Heroic 褋懈谢褜薪褘, 薪芯 Spirit 薪邪 锌懈泻械 褎芯褉屑褘. 袘褍写褍 斜芯谢械褌褜 蟹邪 薪邪褕懈褏!', 11, 0, '2026-06-22 08:30:00'),
(107, 103, 2, 'AK-47 Cyber Force 锌褉芯褋褌芯 芯谐芯薪褜! 校卸械 胁褘斜懈谢, 泻褉邪褋芯褌邪 薪械褉械邪谢褜薪邪褟!', 18, 0, '2026-06-19 14:00:00'),
(108, 103, 6, '150 褉褍斜谢械泄 蟹邪 泻械泄褋? 协褌芯 谐褉邪斜械卸! 袥褍褔褕械 锌芯写芯卸写褍 锌芯泻邪 锌芯写械褕械胁械械褌.', 1, 0, '2026-06-19 15:00:00'),
