INSERT INTO `profile_reviews` (`id`, `author_id`, `target_user_id`, `text`, `created_at`) VALUES
(1, 2, 1, '袝斜谢邪薪 械褖械 褌芯褌', '2026-06-23 19:13:22'),
(2, 6, 1, '邪邪邪邪', '2026-06-24 02:35:16'),
(3, 6, 2, '褎邪褘', '2026-06-24 12:03:57'),
(4, 2, 1, '袨褌谢懈褔薪褘泄 邪胁褌芯褉! 袙褋械谐写邪 懈薪褌械褉械褋薪褘械 懈 邪泻褌褍邪谢褜薪褘械 薪芯胁芯褋褌懈. 袨褋芯斜械薪薪芯 薪褉邪胁褟褌褋褟 芯斜蟹芯褉褘 锌邪褌褔械泄 DOTA 2.', '2026-06-21 07:00:00'),
(5, 6, 1, '啸芯褉芯褕芯 锌懈褕械褌 锌褉芯 泻懈斜械褉褋锌芯褉褌, 卸写械屑 斜芯谢褜褕械 褋褌邪褌械泄 锌褉芯 褌褍褉薪懈褉褘!', '2026-06-22 12:00:00'),
(6, 1, 2, '袦邪薪褟 - 褌芯锌! 袝褢 褋褌邪褌褜懈 锌褉芯 Valorant 胁褋械谐写邪 薪邪 胁褘褋芯褌械. 小锌邪褋懈斜芯 蟹邪 泻邪褔械褋褌胁械薪薪褘泄 泻芯薪褌械薪褌!', '2026-06-23 09:00:00'),
(7, 6, 2, '小芯谐谢邪褋械薪, 芯褌谢懈褔薪褘械 屑邪褌械褉懈邪谢褘 锌芯 褕褍褌械褉邪屑. 袩褉芯写芯谢卸邪泄 胁 褌芯屑 卸械 写褍褏械!', '2026-06-23 15:00:00'),
(8, 1, 6, '袗写屑懈薪 写械谢邪械褌 芯谐褉芯屑薪褍褞 褉邪斜芯褌褍 写谢褟 褋邪泄褌邪. 袦薪芯谐芯 锌芯谢械蟹薪褘褏 褎懈褔 懈 斜褘褋褌褉邪褟 屑芯写械褉邪褑懈褟!', '2026-06-24 07:00:00'),
(9, 2, 6, '袥褍褔褕懈泄 屑芯写械褉邪褌芯褉! 袙褋械谐写邪 褋锌褉邪胁械写谢懈胁褘泄 懈 邪写械泻胁邪褌薪褘泄. 袪械褋锌械泻褌!', '2026-06-24 11:00:00');

